import { useCallback } from 'react';
import { useTranslation } from 'react-i18next';
import i18n from 'i18next';
export interface serverI18nProps {
    i18nKey: string;
    defaultValue: string;
    params?: object;
}
export function useSptTranslation(monitor = true) {
    const { t, i18n } = useTranslation();
    return {
        i18n,
        t: useCallback(
            (key, options = {}) => {
                if (!key) return '';
                if (monitor && !options?.defaultValue?.trim()) {
                    console.error(`i18nKey 加载错误：${key} `);
                    const error =
                        options?.defaultValue === undefined
                            ? new Error(`i18nKey 丢失：${key} `)
                            : new Error(`i18nKey 兜底文案丢失：${key} `);

                    (window as any)?.__OSS_MONITOR_SDK_?.error({
                        message: error.message,
                        stack: error.stack
                    });
                }
                if (typeof key === 'string') {
                    return t(key, options);
                }
                if (typeof key === 'object') {
                    let i18Vo = key as serverI18nProps;
                    return t(i18Vo.i18nKey, {
                        ...i18Vo.params,
                        ...options,
                        // 先使用后端给的，最后使用option的，option为应用本地生成的
                        defaultValue: i18Vo.defaultValue || options.defaultValue
                    });
                }
                return '国际化格式错误，请检查!';
            },
            [t]
        )
    };
}

/**
 * 用于对后端接口返回进行翻译，多用于catch
 * @param key
 * @param options
 * @returns
 */
export const sptI18n = (key: string | serverI18nProps, options: any = {}) => {
    if (!key) return '';
    if (typeof key === 'string') {
        return i18n.t(key, options);
    }
    if (typeof key === 'object') {
        let i18Vo = key as serverI18nProps;
        return i18n.t(i18Vo.i18nKey, { defaultValue: i18Vo.defaultValue, ...i18Vo.params });
    }
    return '国际化格式错误，请检查!';
};
